import { Component, OnInit, OnDestroy } from '@angular/core';
import { Router } from '@angular/router';
import { FormGroup } from '@angular/forms';
import { Subject } from 'rxjs';
import { takeUntil, debounceTime } from 'rxjs/operators';
import { DealFormService } from '../../services/deal-form.service';

@Component({
  selector: 'app-deposit-dates',
  templateUrl: './deposit-dates.component.html',
  styleUrls: ['./deposit-dates.component.scss'],
})
export class DepositDatesComponent implements OnInit, OnDestroy {
  form!: FormGroup;
  private destroy$ = new Subject<void>();

  constructor(
    public svc: DealFormService,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.form = this.svc.depositDatesForm;

    // Auto-persist on changes
    this.form.valueChanges.pipe(
      takeUntil(this.destroy$),
      debounceTime(300),
    ).subscribe(() => this.svc.persist());

    // Auto-calculate maturity date from value date + deposit period
    this.form.get('depositPeriod')?.valueChanges
      .pipe(takeUntil(this.destroy$))
      .subscribe(() => this.recalcMaturity());

    this.form.get('valueDate')?.valueChanges
      .pipe(takeUntil(this.destroy$))
      .subscribe(() => this.recalcMaturity());
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  // ── Deposit type toggle ───────────────────────────────────────────────────

  get isCall(): boolean { return this.svc.isCallDeposit; }

  setDepositType(type: 'Call' | 'Term'): void {
    this.form.get('depositType')?.setValue(type);
  }

  // ── Amount formatting ─────────────────────────────────────────────────────

  get formattedAmount(): string {
    const raw = this.form.get('amount')?.value ?? '';
    const num = parseFloat(raw.toString().replace(/,/g, ''));
    if (isNaN(num)) return raw;
    return num.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  }

  onAmountInput(event: Event): void {
    const raw = (event.target as HTMLInputElement).value.replace(/,/g, '');
    if (/^\d*\.?\d*$/.test(raw)) {
      this.form.get('amount')?.setValue(raw, { emitEvent: true });
    }
  }

  get currencyCode(): string {
    return this.form.get('currency')?.value || '—';
  }

  // ── Maturity auto-calc ────────────────────────────────────────────────────

  private recalcMaturity(): void {
    if (this.isCall) return;
    const period    = this.form.get('depositPeriod')?.value ?? '';
    const valueDate = this.form.get('valueDate')?.value;
    const days      = this.parsePeriodToDays(period);
    if (days && valueDate) {
      const d = new Date(valueDate);
      d.setDate(d.getDate() + days);
      this.form.get('maturityDate')?.setValue(d.toISOString().slice(0, 10));
    }
  }

  private parsePeriodToDays(period: string): number | null {
    const m = period.match(/^(\d+)\s*(day|days|d|month|months|m|year|years|y)/i);
    if (!m) return null;
    const n = parseInt(m[1], 10);
    const u = m[2].toLowerCase();
    if (u.startsWith('d')) return n;
    if (u.startsWith('m')) return n * 30;
    if (u.startsWith('y')) return n * 365;
    return null;
  }

  get periodDays(): number | null {
    return this.parsePeriodToDays(this.form.get('depositPeriod')?.value ?? '');
  }

  get maturityDaysFromValue(): number | null {
    const v = this.form.get('valueDate')?.value;
    const m = this.form.get('maturityDate')?.value;
    if (!v || !m) return null;
    return Math.round((new Date(m).getTime() - new Date(v).getTime()) / 86400000);
  }

  // ── Validation helpers ────────────────────────────────────────────────────

  hasError(field: string): boolean {
    const ctrl = this.form.get(field);
    return !!(ctrl?.invalid && ctrl?.touched);
  }

  // ── Navigation ────────────────────────────────────────────────────────────

  onNext(): void {
    if (this.svc.validateStep(2)) {
      this.svc.persist();
      this.router.navigate(['/deal/interest']);
    }
  }

  get step1Complete(): boolean { return this.svc.isStep1Complete(); }
  get step2Complete(): boolean { return this.svc.isStep2Complete(); }
}
<main class="main" [formGroup]="form">
  <div class="form-card">

    <div class="form-card-header">
      <div class="form-card-header-icon">
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <rect x="2" y="7" width="20" height="14" rx="2"/><path d="M16 7V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2"/>
        </svg>
      </div>
      <div class="form-card-header-text">
        <h2>New Money Market Deal</h2>
        <p>Step 2 of 3 — Enter deposit amount, currency and settlement dates</p>
      </div>
    </div>

    <app-step-progress [currentStep]="2" [step1Complete]="step1Complete" [step2Complete]="step2Complete"></app-step-progress>

    <div class="form-body">

      <!-- ── Deposit Type ── -->
      <div class="form-section-title">Deposit Type</div>
      <div class="field-group" style="margin-bottom: 16px;">
        <label>Deposit Type <span class="req">*</span></label>
        <div class="toggle-group">
          <button type="button"
            class="toggle-btn"
            [class.active-call]="isCall"
            (click)="setDepositType('Call')">Call</button>
          <button type="button"
            class="toggle-btn"
            [class.active-term]="!isCall"
            (click)="setDepositType('Term')">Term</button>
        </div>
      </div>

      <!-- Call info banner -->
      <div *ngIf="isCall" class="call-info">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <circle cx="12" cy="12" r="10"/><line x1="12" y1="16" x2="12" y2="12"/><line x1="12" y1="8" x2="12.01" y2="8"/>
        </svg>
        <span><strong>Call deposit selected.</strong> Maturity date and compounding rule are disabled.</span>
      </div>

      <!-- ── Amount & Currency ── -->
      <div class="form-section-title">Amount &amp; Currency</div>
      <div class="form-grid" style="margin-bottom: 20px;">

        <div class="field-group">
          <label for="currency">Currency <span class="req">*</span></label>
          <input id="currency" type="text" formControlName="currency"
                 maxlength="3" placeholder="e.g. USD"
                 [class.error]="hasError('currency')"
                 style="text-transform:uppercase; letter-spacing:1px; font-weight:500">
          <div *ngIf="hasError('currency')" class="field-error">Enter a valid 3-letter currency code</div>
          <div *ngIf="!hasError('currency')" class="field-hint">ISO 4217 three-letter code</div>
        </div>

        <div class="field-group">
          <label for="amount">Amount <span class="req">*</span></label>
          <div class="field-wrap">
            <span class="amount-prefix">{{ currencyCode }}</span>
            <input id="amount" type="text" inputmode="numeric"
                   class="with-prefix"
                   [class.error]="hasError('amount')"
                   [value]="formattedAmount"
                   (input)="onAmountInput($event)"
                   placeholder="0.00"
                   style="text-align:right; font-variant-numeric:tabular-nums">
          </div>
          <div *ngIf="hasError('amount')" class="field-error">Amount is required</div>
        </div>

      </div>

      <!-- ── Dates ── -->
      <div class="form-section-title">Settlement Dates</div>
      <div class="form-grid" style="margin-bottom: 24px;">

        <!-- Value Date -->
        <div class="field-group">
          <label for="valueDate">Value Date <span class="req">*</span></label>
          <input id="valueDate" type="date" formControlName="valueDate"
                 [class.error]="hasError('valueDate')">
          <div *ngIf="hasError('valueDate')" class="field-error">Value date is required</div>
        </div>

        <!-- Deposit Period -->
        <div class="field-group">
          <label for="depositPeriod">
            Deposit Period <span *ngIf="!isCall" class="req">*</span>
          </label>
          <input id="depositPeriod" type="text" formControlName="depositPeriod"
                 [placeholder]="isCall ? 'N/A — call deposit' : 'e.g. 30 Days, 3 Months'"
                 [class.readonly]="isCall"
                 [attr.readonly]="isCall ? true : null">
          <div *ngIf="!isCall && periodDays" class="field-hint">
            → {{ periodDays }} days from value date
          </div>
          <div *ngIf="!isCall && !periodDays" class="field-hint">
            Type a period to auto-calculate maturity date
          </div>
        </div>

        <!-- Maturity Date -->
        <div class="field-group" [class.is-disabled]="isCall">
          <label for="maturityDate">
            Maturity Date <span *ngIf="!isCall" class="req">*</span>
          </label>
          <div class="field-wrap" style="position:relative">
            <input id="maturityDate" type="date" formControlName="maturityDate"
                   [class.readonly]="isCall"
                   [class.error]="hasError('maturityDate')"
                   [min]="form.get('valueDate')?.value">
            <span *ngIf="isCall" class="disabled-overlay">Not applicable — call deposit</span>
          </div>
          <div *ngIf="hasError('maturityDate')" class="field-error">Maturity date is required for Term</div>
          <div *ngIf="!isCall && maturityDaysFromValue" class="field-hint">
            {{ maturityDaysFromValue }} days from value date
          </div>
        </div>

        <!-- Compounding Rule -->
        <div class="field-group" [class.is-disabled]="isCall">
          <label for="compoundingRule">
            Compounding Rule <span *ngIf="!isCall" class="req">*</span>
          </label>
          <select id="compoundingRule" formControlName="compoundingRule"
                  [class.error]="hasError('compoundingRule')">
            <option value="">{{ isCall ? 'N/A — call deposit' : 'Select compounding rule…' }}</option>
            <option value="none">No Compounding</option>
            <option value="monthly">Monthly</option>
            <option value="quarterly">Quarterly</option>
            <option value="semi-annual">Semi-Annual</option>
          </select>
          <div *ngIf="hasError('compoundingRule')" class="field-error">Compounding rule is required</div>
        </div>

      </div>

    </div><!-- /form-body -->

    <div class="form-footer">
      <button type="button" class="btn btn-ghost" routerLink="/deal/basic-info">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="15 18 9 12 15 6"/></svg>
        Back
      </button>
      <div class="footer-right">
        <button type="button" class="btn btn-ghost" routerLink="/deals">Cancel</button>
        <button type="button" class="btn btn-primary" (click)="onNext()">
          Next: Interest &amp; Calculation
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="9 18 15 12 9 6"/></svg>
        </button>
      </div>
    </div>

  </div>
</main>
